```javascript
// 1. Calculate direction vectors based on bot's Yaw
// In Mineflayer, Yaw 0=South(+Z), -PI/2=East(+X)
const yaw = bot.entity.yaw;
// Right direction vector: (-cos(yaw), 0, -sin(yaw))
const rightVec = new Vec3(-Math.cos(yaw), 0, -Math.sin(yaw));
// Forward direction vector: (-sin(yaw), 0, Math.cos(yaw))
const lookVec = new Vec3(-Math.sin(yaw), 0, Math.cos(yaw));

// 2. Get blocks within 10 blocks radius
const blocks = world.getNearestBlocks(bot, null, 10);

let targetBlock = null;
let maxRightness = -Infinity;
const botPos = bot.entity.position.offset(0, 1.6, 0); // Bot's eye level

for (const block of blocks) {
    // Skip air, water, or lava
    if (block.name === 'air' || block.name === 'water' || block.name === 'lava') continue;

    const blockCenter = block.position.offset(0.5, 0.5, 0.5);
    const toBlock = blockCenter.minus(botPos);
    const dist = toBlock.norm();

    // Exclude blocks too close (min 2 blocks distance) to avoid looking at feet
    if (dist < 2) continue;

    const dir = toBlock.normalize();

    // 3. Field of View filtering (Check if in front)
    // Dot product > 0.5 means roughly within 60 degrees in front
    if (dir.dot(lookVec) < 0.5) continue;

    // 4. Calculate 'rightness' (Project onto right vector)
    const rightness = dir.dot(rightVec);

    // Select the block with the highest rightness score
    if (rightness > maxRightness) {
        maxRightness = rightness;
        targetBlock = block;
    }
}

// 5. Execute movement
if (targetBlock) {
    bot.chat(`Found ${targetBlock.name} to the far right! Moving there.`);
    // Move to the top of the block
    const dest = targetBlock.position.offset(0.5, 1, 0.5);
    await skills.goToPosition(bot, dest.x, dest.y, dest.z, 0.5);
} else {
    bot.chat("Could not find any suitable block in the right field of view.");
}
```
